(window.courseContentFiles = window.courseContentFiles || {})["000003/0005"] = "<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>1</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0; \n    }\n    ul, ol { \n      margin: 0.2em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^(?:---|\\*\\*\\*|___)$/.test(content)) {\n              html.push('<hr>');\n            } else if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: center\">25/26 Колоквиум 4: Полови системи и новородено</h1><blockquote>От тези въпроси ще се паднат 18 въпроса на колоквиума.</blockquote><p><strong>Кое от посочените изменения в женската полова система се приема за преканцерозно състояние:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">дисплазия на епитела на маточната шийка /CIN/</span></strong></li><li>остър цервицит</li><li>миоматозна матка</li><li>жлезиста хиперплазия на маточната шийка</li></ul><p><strong>За фиброаденомът на млечната жлеза е характерно:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">пролиферация на епител и строма</span></strong></li><li>пролиферация само на епител</li><li>пролиферация само на строма</li><li>нито едно от посочените</li></ul><p><strong>Какъв е характерът на процеса при гроздовидна бременност?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">туморен</span></strong></li><li>възпалителен</li><li>дегенеративен</li><li>алергичен</li></ul><p><strong>Коя от изброените кисти на яйчниците е нетуморна:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">фоликуларна</span></strong></li><li>серозна</li><li>муцинозна</li><li>зермоидна</li></ul><p><strong>Кой от посочените морфологични белези се отнася за епителната дисплазия /CINI - III/:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">в епитела се наблюдават нарушен клетъчен поларитет, хиперхромазия и митози</span></strong></li><li>инфилтрация от атипични епителни клетки в подлежащите съдове</li><li>нарушена базална мембрана</li><li>поява на стромна реакция</li></ul><p><strong>Посочете какъв е характерът на стромата при хориокарцинома:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">липсва строма на тумора</span></strong></li><li>обилна, с добре изразена стромна реакция</li><li>рехава, рязко отграничена от тумора</li><li>оскъдна, хиалинизирана</li></ul><p><strong>Коя е най-честата причина за развитието на тубарна бременност:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">срастване и прегъване на маточните тръби</span></strong></li><li>хроничен ендометрит</li><li>кръвен застой</li><li>яйчникова дисфункция</li></ul><p><strong>За обикновената /проста/ хиперплазия на ендометриума не е характерно:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">наличие на клетъчен атипизъм</span></strong></li><li>основен етиологичен фактор са естрогените</li><li>увеличен брой жлези - окръглени, със сравнително гладки граници</li><li>липсва клетъчен атипизъм</li></ul><p><strong>Синдром на Meigs може да се наблюдава при:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">фибром</span></strong></li><li>дисгермином</li><li>кистаденом</li><li>теком</li></ul><p><strong>В кой период от бременността се развива обикновено еклампсия:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">през втората половина на бременността, по време или непосредствено след раждането</span></strong></li><li>в началния период</li><li>през първата половина на бременността</li><li>след спонтанен аборт</li></ul><p><strong>Какви хистологични промени настъпват в маточната лигавица при извънматочна бременност?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">децидуална реакция без хориални въси</span></strong></li><li>хиалинизация на стромата</li><li>децидуална реакция и хориални въси</li><li>хиперемия</li></ul><p><strong>Триадата \"полулунни зъби, глухота, кератит\" се наблюдава при:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">сифилис</span></strong></li><li>HSV</li><li>туберкулоза</li><li>рубеола</li></ul><p><strong>Крукенберговият рак е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">метастаза от слузообразуващ карцином на стомаха в яйчниците</span></strong></li><li>първичен яйчников тумор</li><li>тумор на панкреаса</li><li>метастаза от белодробен карцином в яйчниците</li></ul><p><strong>Кой от посочените процеси е хормонално обусловен?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">жлезиста хиперплазия на маточната лигавица</span></strong></li><li>ендометрит</li><li>папилом</li><li>ендометриоза</li></ul><p><strong>Посочете вярното: при ХМБ/ хиалинно-мембранна болест/, образуваните хиалинни мембрани могат да се наблюдават в:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">и трите изброени</span></strong></li><ul><li>в алвеоли</li><li>алвеоларни ходове</li><li>бронхиоли</li></ul></ul><p><strong>Коя от посочените кисти на яйчниците е НЕтуморна:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">тека лутеинова киста</span></strong></li><li>дермоидна киста</li><li>муцинозен кистаденом</li><li>серозен кистаденом</li></ul><p><strong>Жлезиста хиперплазия на маточната лигавица се наблюдава при жени:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">с гранулозоклетъчен тумор на яйчника</span></strong></li><li>с ендометриоза</li><li>при продължително приемане на андрогенни препарати</li><li>след раждане</li></ul><p><strong>Етиологичен фактор за развитие на рак на маточната шийка е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">инфекция от човешките папиломни вируси (HPV)</span></strong></li><li>инфекция от кандиди</li><li>остър цервицит</li><li>ендоцервикален полип</li></ul><p><strong>Какви са хистологичните промени в лигавицата на матката при ранен аборт?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">децидуална реакция, хориални въси и кръвоизливи</span></strong></li><li>атрофия на ендометриума</li><li>хиперплазия на жлезите в лигавицата на матката</li><li>хроничен ендометрит</li></ul><p><strong>Кой от посочените фактори благоприятства възпалението на плацентата:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">рано изтекли околоплодни води</span></strong></li><li>усукана пъпна връв</li><li>вродени аномалии на плода</li><li>хиалинно-мембранна болест на новороденото</li></ul><p><strong>Ракът на млечната жлеза най-често се локализира в:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">горния външен квадрант</span></strong></li><li>долния вътрешен квадрант</li><li>субареоларно</li><li>централно</li></ul><p><strong>Посочете хистологичните промени в хориалните въси при гроздовидна бременност:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">големи, оточни, с огнищна пролиферация на трофобластния епител</span></strong></li><li>малки, с оскъдна строма и облитерирали съдове</li><li>уголемени, с атрофия на трофобластния епител</li><li>малки, с огнищна пролиферация на трофобластния епител</li></ul><p><strong>Най-честият инвазивен карцином на млечна жлеза е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">дуктален карцином /NOS/</span></strong></li><li>лобуларен карцином</li><li>медуларен карцином</li><li>муцинозен карцином</li></ul><p><strong>Посочете кой фактор благоприятства развитието на ендометрит:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">аборт</span></strong></li><li>субсерозни миоми</li><li>интрамурални лейомиоми</li><li>повишеното ниво на естрогени</li></ul><p><strong>Посочете кой тумор на яйниците е с произход от ембрионалните полови върви:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">гранулозоклетъчен тумор</span></strong></li><li>тумор на бренер</li><li>светлоклетъчен (мезонефроиден)</li><li>серозен кистаденокарцином</li></ul><p><strong>Посочете характерния макроскопски вид на хориокарцинома:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">мековата туморна маса с тъмночервен цвят в ендометриума и мускулатурата</span></strong></li><li>сивкавобелезникава кръгловата туморна маса със снопчест строеж на срез</li><li>кистична формация, изпълнена с множество папиларни разраствания</li><li>възел със сиворозов цвят, с вид на “рибе месо”</li></ul><p><strong>Родовата подутина (caput succedaneum) представлява:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">кръгловата подутина в подкожието на предлежащата част на главата</span></strong></li><li>субпериостален кръвоизлив в областта на някои от плоските черепни кости</li><li>субдурален кръвоизлив</li><li>масивен мозъчен кръвоизлив</li></ul><p><strong>Иктерично оцветяване на ядрата на corpus striatum (kern icterus) се наблюдава при:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">icterus neonatorum gravis</span></strong></li><li>foetus mortus maceratus</li><li>hidrops foetus universalis</li><li>anaemia neonatorum</li></ul><p><strong>По кой от посочените механизми не става инфектирането на плода при листериоза?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">по въздушно-капков път</span></strong></li><li>трансплацентарно</li><li>аспирация</li><li>чрез храносмилателната система</li></ul><p><strong>При прееклампсия се наблюдават:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">хипертония, протеинурия и отоци</span></strong></li><li>хипертония, протеинурия, отоци и припадаци</li><li>хипертония и дизурурия</li><li>всички изброени</li></ul><p><strong>Кефалхематомът представлява:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">субпериостален кръвоизлив в областта на някои от плоските черепни кости</span></strong></li><li>субдурален кръвоизлив</li><li>кръгловата подутина в подкожието на предлежащата част на главата</li><li>масивен мозъчен кръвоизлив</li></ul><p><strong>При кой от изброените карциноми на млечната жлеза клетките се подреждат като в \"индианска нишка\"?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">лобуларен карцином</span></strong></li><li>медуларен карцином</li><li>муцинозен карцином</li><li>дуктален карцином /NOS/</li></ul><p><strong>Какви са хистологичните промени в белите дробове при ХБМ?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">хиперемия, ателектаза и наличие на панделковиден белтъчен материал в алвеолите</span></strong></li><li>кафява индурация на белите дробове</li><li>остър венозен застой</li><li>неутрофилен ексудат в алвеолите</li></ul><p><strong>Каква е хистологичната характеристика на аспирационния синдром на новороденото?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">в дисталните отдели на белите дробове се откриват лануго, епидермални клетки, слуз, кръв, мекониум</span></strong></li><li>компресионна ателектаза</li><li>еритробластоза във вътрешните органи</li><li>интерстициална пневмония</li></ul><p><strong>Може ли при мъж да се позитивира пробата за бременност?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">при хориокарцином</span></strong></li><li>при гинекомастия</li><li>при семином</li><li>при тератом</li></ul><p><strong>Плоскоклетъчният карцином е често срещан тумор на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">маточната шийка</span></strong></li><li>маточното тяло</li><li>яйчниците</li><li>маточните тръби</li></ul><p><strong>Към кои заболявания отнасяме фиброаденома на млечната жлеза?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">доброкачествен тумор</span></strong></li><li>възпалителни заболявания</li><li>злокачествени тумори</li><li>дисхормонално заболяване</li></ul><p><strong>В коя възраст у жената най-често се наблюдава фиброзно-кистозна болест?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">25-50 години</span></strong></li><li>10-15 години</li><li>50-60 години</li><li>60-70 години</li></ul><p><strong>Рисковите фактори за карцином на млечната жлеза са:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">късна менопауза</span></strong></li><li>кърмене</li><li>ранна бременност</li><li>нераждали или с едно дете</li></ul><p><strong>Най-честата форма на извънматочна бременност е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">тубарна</span></strong></li><li>перитонеална</li><li>във влагалището</li><li>яйчникова</li></ul><p><strong>Кои са причините за развитие на тубарна бременност?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">всички заедно</span></strong></li><ul><li>стеснение на маточните тръби</li><li>срастване и прегъване на маточните тръби</li><li>нарушени перисталтични движения</li></ul></ul><p><strong>Извънматочната бременност НЕ може да бъде:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">вагинална</span></strong></li><li>тубарна</li><li>яйчникова</li><li>перитонеална</li></ul><p><strong>Какъв е най-честият изход от тубарна бременност?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">руптура на маточната тръба</span></strong></li><li>нормално износване на бременността</li><li>вторична абдоминална бременност</li><li>развитие на фетус папирацеус</li></ul><p><strong>Кое от посочените заболявания НЕ се отнася към трофобластната болест?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">аборт</span></strong></li><li>гроздовидна бременност</li><li>деструираща мола</li><li>хориокарцином</li></ul><p><strong>Каква е хистологичната картина при изследване на кюретажен материал при ранен аборт?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">кръв, хориални въси, децидуални промени в лигавицата</span></strong></li><li>възпалителни изменения в маточната лигавица</li><li>кръв с децидуални промени в лигавицата, без хориални въси</li><li>маточна лигавица в стадий на пролиферация</li></ul><p><strong>Кой от посочените тумори на яйчниците е изграден от клетки с вид на уроепител?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">тумор на Бренер</span></strong></li><li>лайдигов тумор</li><li>муцинозен кистаденом</li><li>серозен кистаденом</li></ul><p><strong>На кои от посочените места може да се открие лейомиом?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">всички посочени</span></strong></li><ul><li>субмукозно в матката</li><li>субсерозно в матката</li><li>интрамурално в матката</li></ul></ul><p><strong>Какво заболяване е struma ovarii?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">тератом на яйчника</span></strong></li><li>възпаление</li><li>дисхормонално състояние</li><li>герминативноклетъчен тумор</li></ul><p><strong>Плоскоклетъчният карцином е най-чест при:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">маточна шийка</span></strong></li><li>маточното тяло</li><li>яйчниците</li><li>маточни тръби</li></ul><p><strong>Кой е най-често срещаният злокачествен тумор на тестисите?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">семином</span></strong></li><li>тератокарцином</li><li>ембрионален карцином</li><li>тератом</li></ul><p><strong>Каква е консистенцията на простатната жлеза при карцином?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">подчертано плътна</span></strong></li><li>плътна</li><li>меко-еластична</li><li>желеподобна</li></ul><p><strong>Каква е консистенцията на простатната жлеза при бенигнената простатна хиперплазия?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">плътно-еластична</span></strong></li><li>подчертано плътна</li><li>меко-еластична</li><li>желеподобна</li></ul><p><strong>Орхит е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">възпаление на тестиса</span></strong></li><li>възпаление на епидидима</li><li>възпаление на семенните мехурчета</li><li>възпаление на дуктус деференс</li></ul><p><strong>Кои от посочените заболявания на половите органи се отнасят към дисхормоналните?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">жлезиста хиперплазия на ендометриума</span></strong></li><li>салпингит</li><li>псевдоерозио</li><li>ендометрит</li></ul><p><strong>Серозните кистаденоми са яйчникови тумори, които отнасяме към:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">епителните тумори</span></strong></li><li>тумори от половите върви</li><li>метастатични тумори</li><li>мезенхимни тумори</li></ul><p><strong>Какво заболяване е хориокарциномът?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">трофобластен злокачествен тумор</span></strong></li><li>доброкачествен тумор</li><li>възпалително заболяване</li><li>преканцероза</li></ul><p><strong>Към кои заболявания отнасяме фиброаденома на млечната жлеза?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">доброкачествени тумори</span></strong></li><li>възпалителни заболявания</li><li>злокачествени тумори</li><li>дисхормонални заболявания</li></ul><p><strong>Какво заболяване е жлезисто-кистичната болест на млечната жлеза?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">дисхормонално</span></strong></li><li>възпалително</li><li>тумор</li><li>преканцероза</li></ul><p><strong>Гинекомастията е заболяване на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">млечната жлеза при мъжете</span></strong></li><li>млечната жлеза</li><li>яйчниците</li><li>матката</li></ul><p><strong>От кои структури произхожда семиномът на тестиса?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">от епитела на семенните каналчета</span></strong></li><li>от интерстициалните клетки</li><li>от ендотела на кръвоносните съдове</li><li>от зрелите сперматозоиди</li></ul><p><strong>Посочете какъв е по характер патологичният процес при бенигнената простатна хиперплазия</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">хиперпластичен</span></strong></li><li>възпалителен</li><li>туморен</li><li>съдово-циркулаторен</li></ul><p><strong>Бенигнената простатна хиперплазия се наблюдава:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">над 60 години</span></strong></li><li>в детска възраст</li><li>в юношеска възраст</li><li>в зряла възраст (20-50 години)</li></ul><p><strong>Кое от посочените усложнения НЕ може да възникне при бенигнена простатна хиперплазия?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">малформации на пикочните пътища</span></strong></li><li>възпаление на пикочните пътища</li><li>хидронефроза и хидроуретер</li><li>хипертрофия на пикочния мехур</li></ul><p><strong>Кои са най-честите тумори на яйчниците?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">епителните</span></strong></li><li>от половите върви</li><li>метастатичните</li><li>свързаните с уроепитела</li></ul><p><strong>Кои от посочените структури разрастват при бенигнената хиперплазия на простатата?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">едновременно жлези и гладкомускулна строма</span></strong></li><li>кръвоносни съдове</li><li>жлези</li><li>гладкомускулна строма</li></ul><p><strong>По какъв път най-често и рано метастазират туморите на млечната жлеза?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">лимфогенен</span></strong></li><li>хематогенен</li><li>каналикуларен</li><li>по съседство</li></ul><p><strong>В коя възраст най-често се развиват злокачествените тумори на тестиса?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">между 3-то и 5-то десетилетие</span></strong></li><li>между 1-то и 2-то десетилетие</li><li>в ранна детска възраст</li><li>над 70 години</li></ul><p><strong>Какъв е най-честият хистологичен вид на карцинома на простатата?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">аденокарцином</span></strong></li><li>плоскоклетъчен</li><li>хориокарцином</li><li>кистаденокарцином</li></ul><p><strong>Кой от посочените тумори на матката е доброкачествен?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">ендометриален полип</span></strong></li><li>лейомиосарком</li><li>аденомиоза</li><li>цервикален полип</li></ul><p><strong>Кое от изброените образувания на яйчниците НЕ е туморно?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">фоликуларни кисти</span></strong></li><li>шоколадови (ендометриални) кисти</li><li>дермоидни кисти</li><li>лутеинови кисти</li></ul><p><strong>Кой от посочените фактори може да доведе до развитие на жлезиста хиперплазия на ендометриума?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">функциониращи гранулозо- и тека-клетъчни тумори на яйчниците</span></strong></li><li>персистиране на граафови фоликули</li><li>хематогенни инфекции</li><li>фоликуларни кисти</li></ul><p><strong>Кои от изброените хистологични белези са налице при аденокарцином на ендометриума?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">всички изброени</span></strong></li><ul><li>епителът, тапициращ жлезите е атипичен, многореден, на места с разположени на различна височина ядра, много неправилни митози</li><li>жлезите са допрени \"гръб до гръб\"</li><li>базалната мембрана е нарушена</li></ul></ul><p><strong>В кой квадрант на млечната жлеза най-често се локализира фиброаденомът?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">горният външен</span></strong></li><li>горният вътрешен</li><li>долният външен</li><li>долният вътрешен</li></ul><p><strong>Вътрешната ендометриоза се среща в:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">миометриума на матката</span></strong></li><li>яйчници</li><li>маточни тръби</li><li>маточни връзки</li></ul><p><strong>Кое от заболяванията на матката има възпалителна генеза?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">ендометрит</span></strong></li><li>лейомиома</li><li>псевдоерозио</li><li>ендометриоза</li></ul><p><strong>Кое от посочените НЕ е клинико-анатомична форма на простатния карцином?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">язвен</span></strong></li><li>манифестен</li><li>окултен</li><li>латентен</li></ul><p><strong>В кой тестис се развива най-често семиномът?</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\"><strong>десен</strong></span></li><li>ляв</li><li><p>по равно и в двата тестиса</p><br></li><li>в придатъка на тестиса</li></ul><p><strong>Намалената секреция на кои хормони обуславя бенигнената хиперплазия на простатата?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">андрогени</span></strong></li><li>естрогени</li><li>соматотропен хормон</li><li>нито един от изброените</li></ul><p><strong>Кой е най-честият хистологичен вариант на карцинома на простатната жлеза?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">аденокарцином</span></strong></li><li>плоскоклетъчен карцином</li><li>аденосквамозен</li><li>всички посочени</li></ul><p><strong>Къде метастазира най-често по кръвен път простатният карцином?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">кости</span></strong></li><li>черен дроб</li><li>мозък</li><li>бял дроб</li></ul><p><strong>Посочете коя е причината при скирозен карцином на млечната жлеза кожата да придобива характерен вид на \"портокалова кора\"?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">инфилтрация на карцинома в кожата</span></strong></li><li>преобладаването на паренхима</li><li>преобладаването на стромата</li><li>възпалителен процес на кожата</li></ul><p><strong>Кои морфологични белези са характерни за бенигнената простатна хиперплазия?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">едролобулирана срезна повърхност</span></strong></li><li>дребнолобулирана срезна повърхност</li><li>добре оформена капсула</li><li>срастване с околните тъкани</li></ul><p><strong>Кои хормонални нарушения водят до фиброзно-кистична болест?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">повишена естрогенна секреция</span></strong></li><li>намалена естрогенна секреция</li><li>повишена прогестеронова секреция</li><li>намалена прогестеронова секреция</li></ul><p><strong>Торзио на тестиса е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">съдово-циркулаторно</span></strong></li><li>туморно заболяване</li><li>възпалително заболяване</li><li>болест на натрупването</li></ul><p><strong>При инвазивния карцином на шийката на матката НЕ се наблюдават:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">запазени базални мембрани</span></strong></li><li>инфилтрация на атипични клетки под базалната мембрана на епитела</li><li>изразен инфилтративен и деструктивен растеж</li><li>нарушен поларитет и митози</li></ul><p><strong>Кои от посочените туморни процеси на млечната жлеза са доброкачествени?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">всички посочени</span></strong></li><ul><li>аденом</li><li>интрадуктален папилом</li><li>фиброаденом</li></ul></ul><p><strong>Кой е най-честият изход от тубарна бременност?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">руптура на маточната тръба</span></strong></li><li>развитие на литопедион</li><li>изнопсване на бременност</li><li>фетус папирацеус</li></ul><p><strong>Посочете хистологичните промени в хориалните въси при гроздовидна бременност.</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">големи, с оточна строма и редуцирани съдове</span></strong></li><li>огнищна пролиферация на атипичен трофобластен епител</li><li>намалени размери на въсите и плътна фиброзна строма</li><li>големи, с оточна строма и дилатирани съдове</li></ul><p><strong>Хидроцеле на тестиса е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">събиране на серозна течност в туника вагиналис</span></strong></li><li>туморно образувание</li><li>възпалителен процес</li><li>събиране на кръв в туника вагиналис</li></ul><p><strong>От туморите на тестиса най-често срещани са:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">герминативно-клетъчните тумори</span></strong></li><li>стромалните тумори</li><li>туморите от жълтъчното мехурче</li><li>тератомите</li></ul><p><strong>Клетките при семинома не са:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">с изразен полиморфизъм</span></strong></li><li>големи, кръгли, еднообразни</li><li>с богато съдържание на гликоген</li><li>PAS позитивни</li></ul><p><strong>Фиброзно-кистичната болест на гърдата морфологично се представя като:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">огнищни или дифузни промени в двете гърди</span></strong></li><li>единичен туморен възел</li><li>огнищни или дифузни промени в едната гърда</li><li>голяма киста субареоларно</li></ul><p><strong>Острият гноен мастит е характерен за:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">в послеродовия период на лактиращи жени</span></strong></li><li>възрастни жени</li><li>при намален имунитет</li><li>в пубертет</li></ul><p><strong>Рисков фактор за карцинома на шийката на матката не е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">инфекция с трихомонас</span></strong></li><li>чести бременности</li><li>инфекция с HPV вирус</li><li>ранен полов живот</li></ul><p><strong>Кое от изброените не е свързано с ендометриоза?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">причина за извънматочна бременност</span></strong></li><li>аденомиоза</li><li>шоколадова киста в яйчник</li><li>причина за стерилитет</li></ul><p><strong>По снопчестия си строеж лейомиомът хистологично прилича на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">фибром</span></strong></li><li>преходно-клетъчен карцином</li><li>базоцелуларен карцином</li><li>неврином</li></ul><p><strong>При описанието на кой от изброените тумори заради гъсто разположените му структури се използва метафората \"гръб в гръб\"?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">аденокарцином на ендометриума</span></strong></li><li>сарком на матката</li><li>плоскоклетъчен карцином на матката</li><li>базоцелуларен карцином на матката</li></ul><p><strong>Посочете усложнение, при което може да се наблюдава кефалхематома.</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">жълтеница</span></strong></li><li>kern icterus</li><li>хидропс</li><li>pneumonia alba</li></ul><p><strong>Кое от изброените НЕ спада към формите на хемолитичната болест на новороденото?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Хеморагична</span></strong></li><li>Хидропична</li><li>Анемична</li><li>Иктерична</li></ul><p><strong>Триадата на Грег (Gregg) се наблюдава при инфекция с</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">рубеола</span></strong></li><li>цитомегаловирус</li><li>herpes simplex virus</li><li>Epstein-Barr virus</li></ul><p><strong>Коя е най-честата вътреутробна инфекция?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">цитомегаловирус</span></strong></li><li>рубеола</li><li>herpes simplex virus</li><li>Epstein-Barr virus</li></ul><p><strong>При инфекция с кой от изброените микроорганизми се наблюдават везикули по кожата и лигавиците на новороденото?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">herpes simplex virus</span></strong></li><li>листериоза</li><li>ентеровирус</li><li>салмонела</li></ul><p><strong>Кремъчен черен дроб се наблюдава при вътреутробна инфекция с:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Treponema pallida</span></strong></li><li>Listeria monocytogenes</li><li>Toxoplasma Gondii</li><li>Herpes simplex virus</li></ul><p><strong>Триадата на Хътчинсън (Hutchinson) се наблюдава при:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">сифилис</span></strong></li><li>туберкулоза</li><li>листериоза</li><li>токсоплазмоза</li></ul><p><strong>Клетки с ядра, наподобяващи \"око на сова\", се наблюдават при инфекция с:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">цитомегаловирус</span></strong></li><li>рубеола</li><li>herpes simplex virus</li><li>Epstein-Barr virus</li></ul><p><strong>Наличие на лануго, мекониум и слуз в алвеоли и бронхиоли говори за:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">аспирационен синдром</span></strong></li><li>хиалинно-мембранна болест</li><li>интерстициална пневмония</li><li>бронхо-пулмонална дисплазия</li></ul><p><strong>При аспирационния синдром на новороденото аспирацията може да настъпи:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">всички изброени</span></strong></li><ul><li>антенатално</li><li>интрапартално</li><li>постнатално</li></ul></ul><p><strong>Кой от посочените тумори на тестиса е съставен от мономорфна популация от клетки с ядра с везикуларен хроматин и светла цитоплазма?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">класически семином</span></strong></li><li>сперматоцитен семином</li><li>ембрионален карцином</li><li>Yolk sac tumor</li></ul><p><strong>Към герминативноклетъчните тумори на тестиса се отнасят всички изброени освен:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">сертолиевоклетъчен тумор</span></strong></li><li>семином</li><li>хориокарцином</li><li>ембрионален карцином</li></ul><p><strong>Кой от посочените тумори на тестиса е изграден от атипични едноядрени и атипични многоядрени клетки?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">хориокарцином</span></strong></li><li>Yolk sac tumor</li><li>сертолиевоклетъчен тумор</li><li>дермоидна киста</li></ul><p><strong>Кой от посочените тумори на тестиса може да продуцира андрогенни хормони и да доведе до развитие на преждевременен пубертет при момчета и гинекомастия при мъже?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">лайдиговоклетъчен тумор (Leydig cell tumor)</span></strong></li><li>семином</li><li>хориокарцином</li><li>Yolk sac tumor</li></ul><p><strong>Телцата на Schiller-Duval се откриват при:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Yolk sac tumor</span></strong></li><li>хориокарцином</li><li>лайдиговоклетъчен тумор (Leydig cell tumor)</li><li>сперматоцитен семином</li></ul><p><strong>Повишени серумни нива на туморния маркер алфа-фетопротен се откриват при пациенти с:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Yolk sac tumor</span></strong></li><li>хориокарцином</li><li>лайдиговоклетъчен тумор (Leydig cell tumor)</li><li>семином</li></ul><p><strong>За кой от посочените тестикуларни тумори е характерно наличието на лимфоцитен инфилтрат в стромата?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">семином</span></strong></li><li>Yolk sac tumor</li><li>хориокарцином</li><li>лайдиговоклетъчен тумор (Leydig cell tumor)</li></ul><p><strong>Коя от посочените клинични форми НЕ се отнася за простатния карцином?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">мултицентричен</span></strong></li><li>манифестен</li><li>окултен</li><li>латентен</li></ul><p><strong>Аденоматоидният тумор се среща в:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">епидидим</span></strong></li><li>пенис</li><li>тестикуларен паренхим</li><li>простатна жлеза</li></ul><p><strong>За градирането (определяне степента на диференциация) на простатния аденокарцином се използва:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">скала на Gleason</span></strong></li><li>система на Фурман (Furman)</li><li>двустепенна система, разделяща ги на нискостепенни и високостепенни карциноми</li><li>простатният аденокарцином не се градира</li></ul><p><strong>Нарушеният десцензус на тестиса се нарича:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">крипторхизъм</span></strong></li><li>хипоспадия</li><li>еписпадия</li><li>приапизъм</li></ul><p><strong>Болестта на Боуен, засягаща пениса, представлява:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">карцином ин ситу</span></strong></li><li>инвазивен карцином</li><li>вродена аномалия</li><li>възпалително заболяване</li></ul><p><strong>Усложнения на бенигнената простатна хиперплазия са всички изброени освен:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">стриктура на уретер</span></strong></li><li>цистит</li><li>уростаза и калкулоза</li><li>хипертрофия на стената на пикочния мехур</li></ul><p><strong>За простатния аденокарцином са верни твърдения освен:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">негова прекурсорна лезия е бенигнената простатна хиперплазия</span></strong></li><li>може да метастазира в регионалните лимфни възли</li><li>възниква в периферните зони на жлезата</li><li>има повишени стойности на PSA</li></ul><p><strong>За бенигнената простатна хиперплазия е вярно всичко изброено освен:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">възниква при повишени нива на андрогенните хормони</span></strong></li><li>може да има завишени стойности на PSA</li><li>наблюдава се хиперплазия на строма и/или епителни клетки</li><li>засяга преходната зона на жлезата</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Новородено</h1><blockquote>От тези въпроси ще се паднат всичките.</blockquote><p><strong>Родовата подутина (caput succedaneum) представлява:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Кръгловата подутина в подкожието на предлежащата част на главата</span></strong></li><li>Субпериостален кръвоизлив в областта на някои от плоските черепни кости</li><li>Субдурален кръвоизлив</li><li>Масивен мозъчен кръвоизлив</li></ul><p><strong>Иктерично оцветяване на ядрата на corpus striatum (kern icterus) се наблюдава при:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Icterus neonatorum dravis</span></strong></li><li>Foetus mortus maceratus</li><li>Hidrops foetus universalis</li><li>Anaemia neonatorum</li></ul><p><strong>По кой от посочените механизми става инфектирането на плода при листериоза?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Трансплацентарно</span></strong></li><li>Бранхогенно /при аспирация/</li><li>По въздушно-капков път</li><li>Чрез храносмилателната система</li></ul><p><strong>Какви са промените в слезката при сепсис у новороденото:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Увеличена, с мековата консистенция и обилно стържеща се пулпа</span></strong></li><li>Обикновено не показва промени</li><li>Застойна индурация</li><li>С множество хеморагични инфаркти</li></ul><p><strong>Кефалхематомът представлява:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Субпериостален кръвоизлив в областта на някои от плоските черепни кости</span></strong></li><li>Субдурален кръвоизлив</li><li>Кръгловата подутина в подкожието на предлежащата част на главата</li><li>Масивен мозъчен кръвоизлив</li></ul><p><strong>В коя структурна единица на белите дробове се образуват хиалинни мембрани?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">В алвеоларните ходове и алвеолите</span></strong></li><li>Главни бронхи</li><li>Второразредни бронхи</li><li>Само в лумена на алвеолитe</li></ul><p><strong>Какви са хистологичните промени в белите дробове при ХБМ?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Хиперемия, ателектаза и наличие на панделковиден белтъчен материал в алвеолите</span></strong></li><li>Кафява индурация на белите дробове</li><li>Остър венозен застой</li><li>Възпалителни промени в алвеолите</li></ul><p><strong>Каква е хистологичната характеристика на аспирационния синдром на новороденото?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">В дисталните отдели на белите дробове се откриват лануго, епидермални клетки, слуз, кръв, мекониум</span></strong></li><li>Компресионна ателектаза</li><li>Еритробластоза във вътрешните органи</li><li>Интерстициална пневмония</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Новородено (бременност) – клинични задачи </h1><blockquote>От тези въпроси ще се паднат 2 на колоквиума.</blockquote><p><strong>19-годишна примагравида (бременна за първи път жена) получава кървене от гениталиите и коликообразни болки ниско в корема в 12 гестационна седмица. До момента бременността е била неусложнена. Абортира спонтанно. Кой от изброените процеси е най-вероятното обяснение за аборта.</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Хромозомна аномалия</span></strong></li><li>Плацентарна инсуфициенция</li><li>Вродена инфекция</li><li>Токсемия на бременността</li></ul><p><strong>19-годишна жена, втора бременност, второ раждане. Първата бременност завършва с нормално раждане на доносен плод в дома. Настоящата бременност завършва с раждане на бебе с тегло 2990 гр в 35 гестационна седмица. Бебето е оточно и иктерично. Не се установяват вродени аномалии. Хемоглобинът на бебето е 8,5 g/dl. Плацентата също е оточна, но няма възпаление на плацентарните вили или на феталните мембрани. Кое от изброените е най-вероятното обяснение за състоянието на бебето:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Преминаване на антитела на майката през плацентата</span></strong></li><li>Заразяване на майката с рубеола през първия триместър</li><li>Хромозомни аномалии на майката</li><li>Повишени нива на глюкозата в кръвта на майката</li></ul><p><strong>25-годишна жена, 3-та бременност във 39 гестационна седмица. Две нормални предшестващи раждания. От 25 дни не усеща движения на плода. Преди това бременността не е имала усложнения. След разкъсване на околоплодния мехур се ражда мъртъв плод. Микроскопското изследване на околоплодния мехур установява изразен остър хориоамниит. Кой от изброените инфекциозни причинители е отговорен за вътреутробната смърт на плода:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Хемолитичен стрептокок от група В</span></strong></li><li>Токсоплазма гондии</li><li>Херпес симплекс вирус</li><li>Трепонема палидум</li></ul><p><strong>Бебе, родено през 38 гестационна седмица, тежи 2270 гр. Бременността е протекла без усложнения. Не се откриват видими малформации при огледа на детето след раждането, но то изглежда диспропорционално - размерът на главата съответства на гестационната възраст повече, отколкото размера на тялото. Кое от изброените може да обясни находката:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Тютюнопушене през време на бременността</span></strong></li><li>Тризомия 18</li><li>Болест на Ниман-Пик</li><li>Диабет на майката</li></ul><p><strong>Майка забелязва, че 18-месечното й бебе не наддава на тегло през последните 2-3 месеца. Коремът на детето изглежда по-голям от обичайното за възрастта. Физикалното изследване установява обемна маса в горния ляв квадрант на корема. Най-вероятната диагноза е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Невробластом</span></strong></li><li>Рецесивна поликистична болест на бъбреците</li><li>Кистична фиброза (муковисцидоза)</li><li>Кистичен хигром</li></ul><p><strong>Кое от изброените най-добре ни помага да различим \"аборт\" от \"мъртвородено\"</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Възрастта или теглото на плода</span></strong></li><li>Липсата на вродени малформации</li><li>Мацерация на плода</li><li>Наличието на инфекция</li></ul><p><strong>Скоро след раждането се установява респираторен-дисстрес синдром при бебе, родено в 32 гестационна седмица. Бебето тежи 3550 гр. Не се установяват вродени малформации при огледа. Медикаментозно се овладява епизод на хипогликемия. Кой от изброените пренатални тестове на майката предполага тази находка:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Повишен серумен хемоглобин А1С</span></strong></li><li>Повишен хорионгонадотропен хормон</li><li>Полихидрамнион, установен ехографски</li><li>Кариотип 47, XYY при амниоцентеза</li></ul><p><strong>След раждане в 36 гестационна седмица в плацентата се откриват множество полиморфонуклеарни левкоцити по феталните мембрани (хориона и амниона). Това най-често се среща при:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Преждевременно пукване на околоплодния мехур</span></strong></li><li>Herpes simplex инфекция на плода</li><li>Многоплодна бременност</li><li>Abruptio placenta</li></ul><p><strong>Бременна жена се тревожи, че може да роди дете със синдрома на Даун. Каква процедура бихте назначили в пренаталния период, за да разберете дали фетусът има синдрома на Даун:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Амниоцентеза</span></strong></li><li>Ехографско изследване</li><li>Изследване на алфа-фетопротеина на майката</li><li>Изследване на кръвната група на майката</li></ul><p><strong>Раждане в 31 гестационна седмица. Новороденото развива респираторен дисстрес и загива въпреки интубацията и механичната вентилация. След аутопсия микроскопски в белите дробове се откриват множество розови хиалинни мембрани в алвеолите и алвеоларните ходове на белите дробове. Кое от изброените състояния е допринесло най-много за това:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Липса на сърфактант</span></strong></li><li>Тризомия 16</li><li>Пъпна връв с два съда (артерия и вена)</li><li>Диабет на майката</li></ul><p><strong>Раждане в термин. Забелязвате, че плодната част на плацентата, която е с нормална големина, е зеленикаво оцветена. Тази находка е съвместима със:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Мекониално оцветяване</span></strong></li><li>Плацента превия</li><li>Абрупцио на плацентата</li><li>Хориоамнионит</li></ul><p><strong>Ехографското изследване в 16 гестационна седмица на 21-годишна жена установява силно повишено количество амниотична течност (полихидрамнион). Най-вероятно това е резултат от кои аномалии на плода:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Атрезия на дебело черво</span></strong></li><li>Агенезия на бъбреците</li><li>Дефект на междукамерната преграда</li><li>Цитомеголовирусна инфекция</li></ul><p><strong>Забелязвате подуване на корема през първата седмица от живота на дете, родено в термин. Диагностицирате мекониум илеус и насочвате детето за спешна операция. В следоперативния период детето е с персистираща стеаторея и не наддава на тегло. Кой от изброените лабораторни резултати вероятно е свързан със заболяването на детето:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Повишени хлориди при потен тест</span></strong></li><li>HIV +</li><li>Хипербилирубиемия</li><li>Повишени нива на хомованиловата киселина в урината</li></ul><p><strong>Коя от изброените находки е обичайна за пъпната връв на доносено бебе от неусложнена първа бременност на 23-годишна жена:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Изхождане на пъпната връв малко встрани от центъра на плацентата</span></strong></li><li>Дължина 90 см</li><li>Една артерия и една вена</li><li>Единичен възел по средата на пъпната връв</li></ul><p><strong>20-годишна жена с неусложнена бременност не е посещавала личния си лекар по време на бременността. Започва нормално раждане в 38 гестационна седмица, но неочаквано се появява масивно вагинално кръвотечение. Най-вероятното обяснение за това е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Плацента превия</span></strong></li><li>Пролапс на пъпната връв</li><li>Инфаркт на плацентата</li><li>Хориоамниит</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Женска полова система - клинични задачи</h1><blockquote>От тези въпроси ще се паднат 2 на колоквиума.</blockquote><p><strong>36 годишна жена се оплаква от епизодични болки ниско в корема и таза от около 10 г. Гинекологичният преглед и ехографското изследване на тазовите органи не откриват промени. РАР тестът е негативен. Прибягва се до лапароскопия и лекуващият лекар забелязва няколко малки ( 0, 2 до 0, 5 см) синьо-червени нодуларни лезии по серозната повърхност на матката, тръбите и апендикса. Лезиите са ексцизирани и микроскопското изследване показва наличие на ендометриални жлези и строма. Кое от долните твърдения, касаещи заболяването на жената, е най-вероятно:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Може да предизвика диспареуния</span></strong></li><li>Затлъстяването е рисков фактор</li><li>Може да възникне на базата на метаплазия на перитонеалния мезотел</li><li>С развитието на заболяването менструацията спира</li></ul><p><strong>47 годишна жена съобщава за чувствителност при натиск, но без болка ниско в корема от няколко месеца. Ехографското изследване показва 10 см кистична маса в областта на левия яйчник. Чрез ТАБ се взема течност за цитологично изследване, която е бистра, но се откриват групи туморни клетки, заобикалящи псамомни телца. Пациентката най-вероятно има:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Серозен цистаденокарцином на яйчника</span></strong></li><li>Аденокарцином на маточната тръба</li><li>Мезотелиом</li><li>Зрял кистичен тератом на яйчника</li></ul><p><strong>30 годишна жена с инфертилитет се оплаква от епизодични болки ниско в корема от няколко години. Физикалното и гинекологично изследване не установяват туморни маси в малкия таз. РАР тестът установява само малко на брой трихомони и липса на диспластични клетки. Направена е лапароскопия и гинекологът забелязва малки синьо-червени леко надигнати лезии с диаметър 0,2 и 0,4 см по перитонеума, широките лигаменти и Дъгласовото пространство. Тези лезии представляват най-вероятно:</strong></p><ul><li><strong>Ендометриоза</strong></li><li>Метастатичен аденокарцином</li><li>Инфекция с Neisseria gonorrheae</li><li>Кандидоза</li></ul><p><strong>43 годишна жена съобщава, че от няколко месеца менструалните й течения са станали по-обилни и траят по 6-8 дни. Забелязала и епизодични кръвотечения извън цикъла. При гинекологичния прегледа шийката на матката изглежда нормална и РАР тестът не открива абнормни клетки. Гинекологичното изследване установява матка с нодуларност и двойно увеличени размери. Ехографията на надбъбреците не показва патологични промени. Най-вероятно се касае за:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Миоматозна матка</span></strong></li><li>Ендометриален карцином</li><li>Ектопична бременност</li><li>Първичен сифилис</li></ul><p><strong>50 годишна жена забелязала увеличаващи се размери на корема от една година. Физикалното изследване установява свободна течност в коремната кухина, без болезненост, нормална перисталтика. Няма генитално кървене. Ехографското изследване открива аднексиални маси с размери 10 и 7 см. По време на операцията установявате двустранно еднокамерни кисти, изпълнени с бистро съдържимо и папиларни, подобни на цветно зеле, образувания по външната и вътрешната им повърхност. Тези двустранни маси най-вероятно са:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Билатерален серозен кистаденокарцином</span></strong></li><li>Гранулозо-клетъчни тумори</li><li>Зрели кистични тератоми</li><li>Фибросаркома с метастази</li></ul><p><strong>При проведен РАР тест на здрава, сексуално активна 28 годишна жена се откриват цитологични белези за висока степен сквамозна интраепителна лезия (SIL),(респективно PAP IV). Гинекологичният преглед не открива патологични промени. Тази лезия най-вероятно е във връзка със:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Human papillomavirus</span></strong></li><li>Herpes simplex virus инфекция</li><li>Epstein-Barr virus</li><li>Trichomonas vaginalis</li></ul><p><strong>23 годишна жена е приета в болницата с отпадналост и обърканост от 1 ден, трудно контактна. Тестът за бременност е позитивен. Лабораторните изследвания показват констелация, характерна за ДИК (дисеминирано интравазално кръвосъсирване) синдром. Състоянието на пациентката може да се обясни с всички изброени проблеми на бременността, с изключение на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Инфаркт на плацентата</span></strong></li><li>Амниотична емболия</li><li>Еклампсия</li><li>Задържан мъртъв плод</li></ul><p><strong>22 годишна жена изхвърля през вагината гроздовидни маси през 16 седмица на първата си бременност. Не е усещала движения на плода до това време. Направен е кюретаж - от маточната кухина се изваждат около 1000 сс същите гроздовидни маси, представляващи пълни с течност везикули, с размери до 1,5 см. Кой от изброените методи е най-удачен за проследяване състоянието на жената:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Серумен хорионгонадотропен хормон (ХГХ)</span></strong></li><li>Рентгенография на белия дроб</li><li>Ехографско изследване на тазовите органи</li><li>Pap тест</li></ul><p><strong>23 годишна жена е приета в спешен център поради внезапна болка ниско в корема. Гинекологичното изследване установява нормална по размери матка, цервикс и вагина и болезненост при палпация в областта на левите аднекси. Трансвагиналната ехография не установява интраутеринен гестационен сак, но се вижда туморовидна маса с диаметър 2 см в областта на левите аднекси. Кулдоскопията установява наличие на кръв в Дъгласовото пространство. Кое е най-подходящото следващо изследване на този етап:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Изследване на хорионгонадотропен хормон</span></strong></li><li>Рар тест</li><li>Рутинно изследване на урина</li><li>Ендометриална биопсия</li></ul><p><strong>Коя е най-вероятната причина за хемотоколпос при 14 годишно момиче?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Неперфориран химен</span></strong></li><li>Цервикален кондилом</li><li>Руптурирала Бартолинова жлеза</li><li>Цервикална гонорея</li></ul><p><strong>50 годишна жена е забелязала, че през последната 1 година менструалните й кръвотечения са по-обилни и продължителни, средно 7-9 дни. Съобщава и за епизодични метрорагии. През последните 3 месеца е приемала желязосъдържащи препарати за коригиране на анемичен синдром. При гинекологичния преглед цервиксът е непроменен, но матката е с двойно увеличени размери. Трансвагиналната ехография установява наличието на 9 см плътна туморна маса в матката. Направена е хистеректомия. Описаният тумор макроскопски е с вид на рибе месо. Микроскопски, туморът е много целуларен, с вретеновидни клетки, с хиперхромни ядра и 10-20 митози на поле при силно увеличение. Най-вероятната диагноза е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Лейомиосарком</span></strong></li><li>Ендометриален полип</li><li>Аденомиоза</li><li>Ектопична бременност</li></ul><p><strong>Нарушена бременност (изразено кървене във втория триместър) при 31 годишна жена налага извършването на кюретаж. Две седмици след манипулацията кървенето продължава (макар и намаляло) и нивата на хорионгонадропния хормон остават високи. Кое от изброените е най-вероятно да настъпи:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Хориални въси, инвазиращи миометриума</span></strong></li><li>Поява на хеморагични маси в белите дробове</li><li>Спонтанно излекуване</li><li>Установяване на кариотип 46 XY на интраутеринното съдържимо</li></ul><p><strong>33 годишна жена и нейният съпруг искат дете, но тя не може да зачене. Сперматограмата на съпруга е нормална. Кое от изброените е НАЙ-МАЛКО ВЕРОЯТНАТА причина за инфертилитета.</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Хроничен цервицит</span></strong></li><li>Лайдиг-клетъчен тумор</li><li>Пролактином</li><li>Хроничен салпингит/салпингооофорит (Pelvic inflammatory disease)</li></ul><p><strong>19 годишна жена има няколко сиворозови окръглени, леко надигнати (подобни на брадавици) лезии с диаметър 1-2 см по перинеума и вулвата. Биопсията на една от лезиите показва папиларни разраствания, тапицирани с акантотично задебелен и с койлоцитна трансформация многослоен плосък епител. Кое от изброените твърдения е най-вероятно:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Може да настъпи прогресия до плоскоклетъчен карцином</span></strong></li><li>Подобни лезии се срещат често и преди пубертета</li><li>Повечето се откриват в ендометриума</li><li>Имат връзка с кандида инфекция</li></ul><p><strong>При 32 годишна жена, бременна в 18 гестационна седмица, детските сърдечни тонове не се долавят . Ехографското изследване не открива фетус, а само множество ехогенни кисти, изпълващи кухината на матката. Кой от изброените процеси е най-вероятен:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Комплетна мола хидатидоза</span></strong></li><li>Инвазивна мола хидатидоза</li><li>При парциалната мола има фетус</li><li>Хорионкарцином</li></ul><p><strong>Поради абнормен Рар тест е направена цервикална биопсия на 38 годишна жена. Биопсията показва дисплазия, ангажираща цялата дебелина на цервикалния епител. Вашата диагноза е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Цервикална интраепителна неоплазия III (CIN III)</span></strong></li><li>Хроничен обострен цирвицит, свързан със Herpes simplex вирусна инфекция</li><li>Ендоцервикален аденокарцином</li><li>Екстрамамарна болест на Пейджет</li></ul><p><strong>25 годишна жена има тъмнокафяво, неприятно миришещо течение от влагалището, започнало 2 седмици след раждането на доносено здраво дете. Има температура. При гинекологичното изследване се установява леко уголемена матка и болезненост при палпация. Нивото на Хорионгонатропният хормон в кръвта е нормално. Кое от изброените състояния е най-вероятно:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Задържани плацентарни части</span></strong></li><li>Инвазивна мола</li><li>Дегенериращ лейомиом</li><li>Синдром на Шийхан</li></ul><p><strong>39 годишна жена има дисменорея от няколко месеца. Рар тестът и тестът за бременност са негативни. При гинекологичното изследване не се установяват туморни маси в аднексите. Цервиксът е нормален. Матката е дифузно увеличена с размери три пъти над нормата, без туморни формации и с почти нормална по размери кухина. Направена е тотална хистеректомия. Каква микроскопска находка е най-вероятно да бъде установена:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>Хиперхромни и плейоморфни гладкомускулни клетки с изразена митотична активност</p><br></span></strong></li><li>Ендометриални жлези и строма в миометриума</li><li>Атипични жлези, инвазиращи стената на матката</li><li>Големи, аваскуларни хориални въси с трофобластна пролиферация</li></ul><p><strong>При преглед на 22 годишна жена се установяват няколко сиворозови, леко надигнати лезии с неравна повърхност и размери 0,5-1 см в областта на перинеума. Една от тях е изследвана микроскопски и се установява папиларно разрастване, тапицирано с многослоен плосък епител и койлоцитни промени. Какво е значението на тези лезии:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Може да има прогресия до in situ и инвазивен карцином</span></strong></li><li>Жената трябва да бъде лекувана за гонококова инфекция</li><li>Трябва да се търси подлежаща малигненост</li><li>Лезиите са белези на синдрома на Търнър</li></ul><p><strong>55 годишна жена се оплаква от болки ниско в корема. Преди 25 години е направена обикновена хистеректомия. При ехографското и лапароскопско изследване в областта на левия яйчник се установява туморна маса с диаметър 9 см. Хистологично се откриват полиморфни туморни жлези, напомнящи ендометриалните. Какъв патологичен процес е имало в премахнатата преди 25 години матка?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Ендометриоза по серозната повърхност на матката, тръбите и лигаментите</span></strong></li><li>Аденомиоза</li><li>Хроничен ендометрит</li><li>Ендометриална хиперплазия</li></ul><p><strong>38 годишна жена се оплаква от бяло, като „пресечено мляко“ вагинално течение от няколко седмици. Не съобщава за извънменструално кървене. Рар тестът показва нормален плосък епител, единични левкоцити и псевдохифи. Кой от изброените инфекциозни агенти най-вероятния причинител:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Candida albicans</span></strong></li><li>Treponema pallidum</li><li>Herpes simplex</li><li>Escherichia coli</li></ul><p><strong>35 годишна жена се оплаква от тъпи болки ниско в корема от няколко месеца. Гинекологичното изследване установява нормален цервикс и матка, а в левия аднекс се палпира голяма и болезнена при палпация туморна маса. Ехографски се открива 8 см кистична маса в левия яйчник, изпълнена с течност. По време на лапаротомията се установяват множество нишковидни сраствания в малкия таз. Овариалният тумор е изрязан и изследван в Центъра по патология. Макроскопски се установява кистична формация, изпълнена с гноевиден ексудат. Микроскопски в стената на кистата се откриват остатъци от маточна тръба и яйчник. Кой от изброените инфекциозни агенти най-вероятно е довел до тази находка:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Neisseria gonorrheae</span></strong></li><li>Human papillomavirus</li><li>Mycobacterium tuberculosis</li><li>Trichomonas vaginalis</li></ul><p><strong>Поради маточни кръвотечения от няколко месеца, жена на 62 години посетила личния си лекар. Жената никога не е забременявала и от 15 години е в менопауза. Личният й лекар я насочва към гинеколог, който извършва ендометриална биопсия. Морфологичният отговор е добре диференциран ендометриален карцином. При тази ситуация, ако се открие яйчников тумор, той най-вероятно ще бъде:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Гранулозоклетъчен тумор</span></strong></li><li>Папиларен серозен кистазнокарцином</li><li>Крукенбертов тумор</li><li>Незрял тератом</li></ul><p><strong>56 годишна бездетна жена е в менопауза от 9 години. Съобщава за маточно кървене в последните седмици. Кой от изброените диагностични методи е най-подходящ:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Ендометриална биопсия</span></strong></li><li>Рар тест</li><li>Компютър томографско изследване на малкия таз</li><li>Колпоскопия</li></ul><p><strong>50 годишна жена съобщава за дискомфорт ниско в корема от няколко месеца. Направеното КТ изследване установява лобулирани кистични билатерални лезии в областта на яйчниците с размери 10 и 8 см. Коя от изброените неоплазми е най-вероятна:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Серозен кистаденокарцином</span></strong></li><li>Зрял кистичен тератом</li><li>Фибротеком</li><li>Муцинозен цистаденом</li></ul><p><strong>8 годишна жена забелязва оскъдно кървене извън менструалните цикли през последните 2 месеца. Гинекологичното изследване не открива цервикални лезии и Рар тестът е отрицателен. Извършена е ендометриална биопсия с отговор - жлезиста хиперплазия на ендометриума. Ехографското изследване установява туморна маса в левия яйчник. Най-вероятно това е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Фибротекома</span></strong></li><li>Зрял кистичен тератом</li><li>Крукенбергов тумор</li><li>Сертоли-Лайдигов тумор</li></ul><p><strong>От известно време 35 годишна жена е с неясни оплаквания от лесна умора и общ дискомфорт. Установявате субфебрилна температура, ингвинална лимфаденопатия и дифузен обрив по тялото. Кожната биопсия открива дифузни периваскуларни инфилтрати от плазматични клетки. Кой от изброените инфекциозни причинители е най-вероятно отговорен за оплакванията на жената:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Treponema pallidum</span></strong></li><li>Herpes simplex</li><li>Candida albicans</li><li>Neisseria gonrrheae</li></ul><p><strong>Ехографски е установена туморна маса в десния яйчник на 40 годишна жена. При лапаротомията се намира кистичен тумор, прикрепен към яйчника. Повърхността на кистата е с макроскопски видими папиларни разраствания. Кой критерий е най-сигурен при разграничаването на \"граничен серозен тумор\" от серозен цистаденокарцином:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Инвазия на овариалната строма</span></strong></li><li>Ангажирането и на другия яйчник</li><li>Наличието на псамомни телца</li><li>Клетъчна атипия</li></ul><p><strong>Получавате хистологичен отговор на кюретажен материал: „Ендометриални жлези в пролиферативна фаза и морфологични данни за хроничен ендометрит“. Ще го интерпретирате като:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Промени, предизвикани от интраутеринна спирала</span></strong></li><li>Премалигнена ендометриална лезия</li><li>Хиперестрогенно състояние</li><li>Синдром на Щайн-Льовентал<em></em></li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">От Word Файл въпроси, които ги няма в другия</h1><p><strong>Кой от посочените тумори на млечната жлеза се развива от епитела на млечните канали?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Интрадуктален папилом</span></strong></li><li>Фиброаденом</li><li>Филоиден фиброаденом</li><li>Лобуларен карцином</li></ul><p><strong>Коя от изброените кисти на яйчниците е НЕ-туморна?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Фоликуларна</span></strong></li><li>Серозна</li><li>Муцинозна</li><li>Тумор на Бренер</li></ul><p><strong>За фиброаденома на млечната жлеза са характерни следните микроскопски белези:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Пролиферация на епителни и мезенхимни компоненти на каналите</span></strong></li><li>Пролиферация на епителни и мезенхимни компоненти на лобулите</li><li>Пролиферация на епителни компоненти на лобулите</li><li>Пролиферация на мезенхимни компоненти на лобулите</li></ul><p><strong>Кой от изброените тумори на яйчниците е злокачествен:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Дисгермином</span></strong></li><li>Тумор на Бренер</li><li>Кистаденом</li><li>Теком</li></ul><p><strong>Към преканцерозите на млечната жлеза се отнася:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Фиброаденом</span></strong></li><li>Папилом</li><li>Дуктална хиперплазия</li><li>Лобуларен неинвазивен рак</li></ul><p><strong>Кой е морфологичния белег, говорещ за вероятния алергичен характер на еклампсията?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Фибриноидна некроза на артериалните съдови стени</span></strong></li><li>Неспецифичен амниит</li><li>Хиалинна дегенерация</li><li>Грануломатозен ангиит</li></ul><p><strong>За простата жлезиста хиперплазия на маточната лигавица са характерни следните белези:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Хиперплазия на ендометриалните жлези</span></strong></li><li>Възпалителни промени в стромата</li><li>Оскъдна строма, с разположени „гръб до гръб” жлези в нея</li><li>Базалните мембрани на жлезите са разрушени</li></ul><p><strong>Коя от посочените кисти на яйчниците е НЕ-туморна?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Лутеинова</span></strong></li><li>Дермоидна киста</li><li>Муцинозен кистаденом</li><li>Серозен кистаденом</li></ul><p><strong>Към инфилтративните карциноми на млечната жлеза се отнася:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Комедо</span></strong></li><li>Тубуларен</li><li>Микропапиларен</li><li>Крибриформен</li></ul><p><strong>С какво се характеризират морфологичните промени във вътрешните органи при еклампсия?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Тежки микроциркулаторни нарушения и фибриноидна некроза в стените на кръвоносните съдове</span></strong></li><li>Развитие на остър венозен застой</li><li>Развитие на артериална хиперемия</li><li>Хиперплазия на лимфните възли</li></ul><p><br></p><br><br><style></p><p>    body { </p><p>      font-family: \"Open Sans\", Arial, sans-serif; </p><p>      max-width: 1200px; </p><p>      margin: 2rem auto; </p><p>      padding: 0 1rem; </p><p>      line-height: 1.6; </p><p>      color: #1f2937; </p><p>    }</p><p>    h1 { </p><p>      font-weight: 600; </p><p>      font-size: 1.5em;</p><p>      margin-top: 1.5em;</p><p>      margin-bottom: 0.5em;</p><p>      color: #3a5a40;</p><p>      border-bottom: 2px dashed #a3b18a;</p><p>      padding-bottom: 5px;</p><p>    }</p><p>    p { </p><p>      margin: 0.7em 0 1.5em 0; </p><p>      white-space: pre-wrap;</p><p>    }</p><p>    @media (max-width: 768px) {</p><p>      body { font-size: 16px; }</p><p>      h1 { font-size: 1.3em; }</p><p>    }</p><p>  </style>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>";
